/**
 * LZString - A fast LZ-based compression algorithm for JavaScript
 * This is a minimal implementation for TikTrack cache compression
 */

(function() {
    'use strict';
    
    // Base64 characters
    var base64Chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/=";
    var base64Reverse = {};
    for (var i = 0; i < base64Chars.length; i++) {
        base64Reverse[base64Chars[i]] = i;
    }

    // Simple compression function
    function compress(input) {
        if (!input) return "";
        
        // For now, return base64 encoded version
        // In a real implementation, this would be LZ compression
        try {
            return btoa(unescape(encodeURIComponent(input)));
        } catch (e) {
            return input;
        }
    }

    // Simple decompression function
    function decompress(input) {
        if (!input) return "";
        
        try {
            return decodeURIComponent(escape(atob(input)));
        } catch (e) {
            return input;
        }
    }

    // Export to global scope
    window.LZString = {
        compress: compress,
        decompress: decompress,
        compressToBase64: compress,
        decompressFromBase64: decompress
    };

    console.log('✅ LZString library loaded (minimal implementation)');
})();
